import React, { useState, useEffect } from 'react';
import axios from 'axios';

const App = () => {
  const [user, setUser] = useState({});
  const [otp, setOtp] = useState('');
  const [qrCode, setQrCode] = useState(null);

  useEffect(() => {
    axios.get('https://api.example.com/user')
      .then(res => setUser(res.data))
      .catch(err => console.error(err));
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    axios.post('https://api.example.com/otp', { otp })
      .then(res => console.log(res.data))
      .catch(err => console.error(err));
  };

  const handleScan = (e) => {
    e.preventDefault();
    axios.get('https://api.example.com/qr-code', { responseType: 'blob' })
      .then(res => setQrCode(URL.createObjectURL(res.data)))
      .catch(err => console.error(err));
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white shadow-md p-4 rounded-md w-full max-w-md">
        <h2 className="text-lg font-bold mb-4">Multi-Factor Authentication</h2>
        <form onSubmit={handleSubmit}>
          <label className="block mb-2">OTP:</label>
          <input type="text" value={otp} onChange={(e) => setOtp(e.target.value)} className="block w-full p-2 mb-4"/>
          <button type="submit" className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">Submit</button>
        </form>
        <div className="mt-4">
          <button onClick={handleScan} className="bg-[#B7D7CD] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded">Scan QR Code</button>
          {qrCode && <img src={qrCode} alt="QR Code" className="mb-4"/>}
        </div>
        <div className="bg-[#B7D7CD] shadow-md p-4 rounded-md w-full max-w-md mt-4">
          <h2 className="text-lg font-bold mb-4">User Information</h2>
          <ul>
            {Object.keys(user).map((key) => (
              <li key={key}>{key}: {user[key]}</li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};

export default App;
